esqlQuery.esql:
TS metrics-ibmmq.otel-*
| STATS
    failed_conns = SUM(RATE(ibmmq_qmgr_failed_mqconn_mqconnx_total)),
    failed_opens = SUM(RATE(ibmmq_qmgr_failed_mqopen_total))
    BY attributes.qmgr
| EVAL total_failed_access = COALESCE(failed_conns, 0) + COALESCE(failed_opens, 0)
// Alert when connection or object-open failures are detected
// Failures indicate authentication problems, resource exhaustion,
// or network issues between clients and the queue manager
// Adjust threshold based on your environment
| WHERE total_failed_access > 0
